def gen(rng, size):
    n = rng.randint(3, max(3, min(size, 100)))
    while True:
        s = ''.join(rng.choice('abcdefghij') for _ in range(n))
        from collections import Counter
        freq = Counter(s)
        odds = [v for v in freq.values() if v % 2 == 1]
        evens = [v for v in freq.values() if v % 2 == 0]
        if odds and evens:
            return [s]

