class Solution:
    def maxDifference(self, s):
        best = None
        for a in set(s):
            for b in set(s):
                if a == b:
                    continue
                fa = s.count(a)
                fb = s.count(b)
                if fa % 2 == 1 and fb % 2 == 0:
                    diff = fa - fb
                    if best is None or diff > best:
                        best = diff
        return best

