class Solution:
    def maxDifference(self, s):
        from collections import Counter
        freq = Counter(s)
        odd_max = None
        even_min = None
        for v in freq.values():
            if v % 2 == 1:
                if odd_max is None or v > odd_max:
                    odd_max = v
            else:
                if even_min is None or v < even_min:
                    even_min = v
        return odd_max - even_min

