var maxDifference = function(s) {
    const freq = new Array(26).fill(0);
    for (const ch of s) freq[ch.charCodeAt(0) - 97]++;
    let oddMax = null, evenMin = null;
    for (const v of freq) {
        if (v === 0) continue;
        if (v % 2 === 1) {
            if (oddMax === null || v > oddMax) oddMax = v;
        } else {
            if (evenMin === null || v < evenMin) evenMin = v;
        }
    }
    return oddMax - evenMin;
};
